// components/MarketplaceHome.jsx
import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';

const MarketplaceHome = ({ token }) => {
    const [listings, setListings] = useState([]);
    const [searchKeyword, setSearchKeyword] = useState('');
    const [selectedCategory, setSelectedCategory] = useState('');

    const loadPlatformOffers = async () => {
        try {
            let url = `http://localhost:5000/api/listings/search?`;
            if (selectedCategory) url += `category=${encodeURIComponent(selectedCategory)}&`;
            if (searchKeyword) url += `keyword=${encodeURIComponent(searchKeyword)}`;

            const response = await fetch(url);
            const data = await response.json();
            if (data.success) setListings(data.listings);
        } catch (err) {
            console.error('Error establishing database state synchronization loops:', err);
        }
    };

    useEffect(() => {
        loadPlatformOffers();
    }, [selectedCategory]);

    return (
        <div>
            <div style={{ display: 'flex', gap: '15px', marginBottom: '30px' }}>
                <input 
                    type="text" 
                    placeholder="Search local student hustles (e.g., tailoring, baking, tutoring)..." 
                    style={{ flex: 1, padding: '12px', borderRadius: '4px', border: '1px solid #ccc', fontSize: '1em' }}
                    value={searchKeyword}
                    onChange={(e) => setSearchKeyword(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && loadPlatformOffers()}
                />
                <button onClick={loadPlatformOffers} style={{ background: '#0288d1', color: 'white', border: 'none', padding: '0 25px', borderRadius: '4px', cursor: 'pointer', fontWeight: 'bold' }}>Search</button>
            </div>

            <div style={{ display: 'flex', gap: '10px', marginBottom: '30px', flexWrap: 'wrap' }}>
                {['', 'Graphics & Design', 'Tech & Repairs', 'Food & Baking', 'Apparel & Tailoring'].map((cat) => (
                    <button 
                        key={cat} 
                        onClick={() => setSelectedCategory(cat)}
                        style={{ padding: '8px 16px', borderRadius: '20px', border: selectedCategory === cat ? 'none' : '1px solid #ccc', background: selectedCategory === cat ? '#0288d1' : '#fff', color: selectedCategory === cat ? '#fff' : '#333', cursor: 'pointer' }}
                    >
                        {cat === '' ? 'All Services' : cat}
                    </button>
                ))}
            </div>

            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: '25px' }}>
                {listings.length === 0 ? (
                    <p style={{ gridColumn: '1/-1', textAlign: 'center', color: '#777' }}>No campus catalog offers match your search parameter vectors.</p>
                ) : (
                    listings.map((item) => (
                        <div key={item.id} style={{ border: '1px solid #e0e0e0', borderRadius: '8px', padding: '20px', display: 'flex', flexDirection: 'column', justifyContent: 'space-between', boxShadow: '0 2px 4px rgba(0,0,0,0.02)' }}>
                            <div>
                                <span style={{ background: '#e1f5fe', color: '#0288d1', fontSize: '0.8em', padding: '4px 8px', borderRadius: '4px', fontWeight: 'bold' }}>{item.category_name}</span>
                                <h4 style={{ margin: '10px 0 5px 0', fontSize: '1.2em' }}>{item.title}</h4>
                                <p style={{ color: '#666', fontSize: '0.9em', margin: '0 0 15px 0', minHeight: '40px' }}>{item.description}</p>
                            </div>
                            <div style={{ borderTop: '1px solid #eee', paddingTop: '15px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                <div>
                                    <span style={{ fontSize: '0.8em', color: '#999', display: 'block' }}>Provider</span>
                                    <strong style={{ fontSize: '0.95em' }}>{item.seller_name}</strong>
                                </div>
                                <div style={{ textAlign: 'right' }}>
                                    <span style={{ fontSize: '1.3em', fontWeight: 'bold', color: '#2e7d32' }}>KSh {parseFloat(item.price).toLocaleString()}</span>
                                    {token ? (
                                        <Link to={`/booking/${item.id}`} style={{ display: 'block', color: '#0288d1', fontSize: '0.85em', textDecoration: 'none', marginTop: '4px', fontWeight: 'bold' }}>Book Discovery →</Link>
                                    ) : (
                                        <span style={{ display: 'block', color: '#777', fontSize: '0.8em', fontStyle: 'italic' }}>Login required</span>
                                    )}
                                </div>
                            </div>
                        </div>
                    ))
                )}
            </div>
        </div>
    );
};

export default MarketplaceHome;
